SELECT DISTINCT Addresses.address_id, Addresses.line_1, Addresses.line_2, Addresses.line_3, Addresses.city, Addresses.zip_postcode, Addresses.state_province_county, Addresses.country, Addresses.other_address_details
FROM Addresses
INNER JOIN Students ON Students.current_address_id = Addresses.address_id;

SELECT Professionals.professional_id, Professionals.role_code, Professionals.email_address
FROM Professionals
WHERE Professionals.professional_id NOT IN (SELECT professional_id FROM Treatments);
